const body = $input.first().json.body;
const assetPackage = body.asset_package || {};
const deliveryMethod = $env.DELIVERY_METHOD || 'email';

return [{
  json: {
    ...assetPackage,
    delivery_method: deliveryMethod,
    delivery_start: new Date().toISOString()
  }
}];

const pkg = $input.first().json;
const customer = pkg.customer || {};
const products = pkg.products || [];

let emailBody = `<h2>Your Product Assets - Order #${pkg.order_id}</h2>`;
emailBody += `<p>Hi ${customer.name},</p>`;
emailBody += `<p>Your product assets are ready! Here's what's included:</p>`;

for (const product of products) {
  emailBody += `<hr><h3>${product.name} (SKU: ${product.sku})</h3>`;
  emailBody += `<p><strong>Quantity:</strong> ${product.quantity}</p>`;

  if (product.images && product.images.length > 0) {
    emailBody += `<p><strong>Images:</strong></p><ul>`;
    product.images.forEach(img => {
      emailBody += `<li><a href="${img}">${img}</a></li>`;
    });
    emailBody += `</ul>`;
  }

  if (product.videos && product.videos.length > 0) {
    emailBody += `<p><strong>Videos:</strong></p><ul>`;
    product.videos.forEach(vid => {
      emailBody += `<li><a href="${vid}">${vid}</a></li>`;
    });
    emailBody += `</ul>`;
  }

  if (product.description) {
    emailBody += `<p><strong>Description:</strong></p><p>${product.description}</p>`;
  }
}

emailBody += `<hr><p>Thank you for your order!</p>`;

return [{
  json: {
    ...pkg,
    email_body: emailBody,
    email_subject: `Your Product Assets - Order #${pkg.order_id}`
  }
}];

return [{
  json: {
    delivery_success: true,
    order_id: $json.order_id,
    customer_email: $json.customer.email,
    delivered_at: new Date().toISOString()
  }
}];

return [{
  json: {
    delivery_success: false,
    order_id: $json.order_id,
    customer_email: $json.customer.email,
    error: $json.error || 'Email delivery failed',
    failed_at: new Date().toISOString()
  }
}];
